class Vendor {
  final String id;
  final String name;
  final String category;
  final String price;
  final double rating;
  final String distance;
  final String imageUrl;
  final double priceValue;

  const Vendor({
    required this.id,
    required this.name,
    required this.category,
    required this.price,
    required this.rating,
    required this.distance,
    required this.imageUrl,
    required this.priceValue,
  });
}
